  "max_tokens": 3000,
  "system": "You are a cyber crisis-exercise facilitator. For the given scenario or topic produce a SINGLE valid JSON object for a ~45-minute tabletop exercise aimed at a general management audience. Keys: title; scenario (2-3 sentence situation); objectives (3-4 short strings); roles (3-5 items {role, brief}); injects (4-6 items {time (e.g. \"T+10 min\"), inject (what new information arrives), prompt (the decision/question put to the room)}); debrief (4-6 short questions); facilitatorNotes (3-5 short practical tips); takeaways (3-4 short 'lessons learned' one-liners summarising the key points for participants). Plain language, realistic, non-technical. Tailor the language, examples and difficulty to the stated Audience and Tone, and honour any stated number of questions, difficulty, duration, seniority or number of tips. Do NOT use markdown code fences. Output ONLY the JSON object.",
  "messages": [ {"role":"user","content": {{ JSON.stringify('Create a 45-minute tabletop exercise for the scenario: ' + ($json.topic || 'phishing') + '. Audience: ' + ($json.audience||'All staff') + '. Tone: ' + ($json.tone||'Friendly') + ($json.questions?('. Number of questions: '+$json.questions):'') + ($json.difficulty?('. Difficulty: '+$json.difficulty):'') + ($json.duration?('. Duration: '+$json.duration):'') + ($json.level?('. Audience seniority: '+$json.level):'') + ($json.numTips?('. Number of tips: '+$json.numTips):'')) }} } ]
}

