var JKIT_CSS=".jkit-take{background:#F4F6F9;border:1px solid #E2E6EC;border-left:4px solid #0E7C86;border-radius:10px;padding:14px 18px;margin:22px 0 0;page-break-inside:avoid}.jkit-take .th{font-family:-apple-system,'Segoe UI',Arial,sans-serif;font-size:11px;letter-spacing:2px;text-transform:uppercase;color:#0A1A2F;font-weight:800;margin:0 0 7px}.jkit-take ul{margin:0;padding-left:18px}.jkit-take li{font-size:13.5px;line-height:1.5;color:#2b3340;margin:5px 0}.jkit-sign{display:flex;align-items:center;gap:12px;margin:20px 0 0;padding-top:14px;border-top:2px solid #0E7C86;page-break-inside:avoid}.jkit-sign img,.jkit-sign .jav{width:46px;height:46px;border-radius:50%;border:2px solid #0E7C86;flex:0 0 auto}.jkit-sign .nm{font-family:Georgia,serif;font-size:15px;color:#0A1A2F;font-weight:700}.jkit-sign .rl{font-family:-apple-system,'Segoe UI',Arial,sans-serif;font-size:10px;letter-spacing:2px;text-transform:uppercase;color:#0E7C86;font-weight:800;margin-top:2px}";
function jKitEsc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
function jTakeBox(takeaways){ var t=(takeaways||[]).filter(Boolean).slice(0,4); if(!t.length) return ''; return '<div class="jkit-take"><div class="th">Key takeaways &middot; Lessons learned</div><ul>'+t.map(function(x){return '<li>'+jKitEsc(x)+'</li>';}).join('')+'</ul></div>'; }
function jSignoff(){ var av=jAvatarUri(); var avatar=av?('<img src="'+av+'"/>'):JKIT_SVG; return '<div class="jkit-sign">'+avatar+'<div><div class="nm">Jarvis</div><div class="rl">Your AI Awareness Assistant</div></div></div>'; }
function jKitBlock(takeaways){ return jTakeBox(takeaways)+jSignoff(); }

const d=$json.data||{}; const topic=$json.topic||'Incident'; const date=$json.date||''; const client=($json.client||'').toString();
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
const byline=client?('Prepared for '+client):'Security Awareness';
function ul(a){ return '<ul>'+((a||[]).map(function(x){return '<li>'+esc(x)+'</li>';}).join(''))+'</ul>'; }
var roles=((d.roles||[]).map(function(r){return '<tr><td class="rl">'+esc(r.role)+'</td><td>'+esc(r.brief)+'</td></tr>';}).join(''));
var injects=((d.injects||[]).map(function(x,i){return '<div class="card"><span class="pill">'+esc(x.time||('Inject '+(i+1)))+'</span><p style="margin:8px 0 6px"><b>'+esc(x.inject)+'</b></p><p style="margin:0;color:#0E7C86"><b>Discuss:</b> '+esc(x.prompt)+'</p></div>';}).join(''));
